package main
import "fmt"
func main() {
    qtd := 0
    fmt.Scan(&qtd)
    artistas := []int{}
    for i := 0; i < qtd; i++ {
        var artista int
        fmt.Scan(&artista)
        artistas = append(artistas, artista)
    }
    fmt.Println(contarProtegidos(artistas))
}

func contarProtegidos(pessoas []int) int {
    desprotegidos := 0

    for i := 0; i < len(pessoas); i++{
        if pessoas[i] == 1{
            continue
        }

        if i == 0 {
            if pessoas[i+1] == 0 {
                desprotegidos++
            }
        } else if i == len(pessoas) - 1{
            if pessoas[i - 1] == 0 {
                desprotegidos++
            }
        } else {
            if pessoas[i+1] == 0 && pessoas[i-1] == 0 {
                desprotegidos++
            }
        }
    }
    return desprotegidos
}
